};
use std::path::PathBuf; fn main() -> Result<(), Box<dyn std::error::Error>> { let home = PathBuf::from("/my/env/home"); let env = Environment::open( EnvironmentConfig::new(home) .with_allow_create(true) .with_transactional(true), )?; let db = env.open_database( None, "sampleDatabase", &DatabaseConfig::new() .with_allow_create(true) .with_transactional(true), )?; let key = DatabaseEntry::from_bytes(b"thekey"); let data = DatabaseEntry::from_bytes(b"thedata"); // Begin a transaction. let txn = env.begin_transaction(None, None)?; // Perform the write under the transaction. match db.put(Some(&txn), &key, &data) { Ok(_) => { txn.commit()?; println!("Write committed."); } Err(e) => { txn.abort()?; println!("Write failed, transaction aborted: {}", e); } } db.close()?; env.close()?; Ok(())
} Key rules: Obtain a transaction with env.begin_transaction(parent, config). Pass None for the parent. Nested (child) transactions are not supported in v1.5 ; passing Some(&parent) returns a typed NoxuError::Unsupported error. See docs/src/internal/v1.5-decisions-2026-05.md Decision 3B; the parent parameter is scheduled for removal in v2.0. Pass Some(&txn) as the first argument to db.put(), db.get(), db.delete(), and db.open_cursor(). Commit with txn.commit() or roll back with txn.abort(). Once committed or aborted, a transaction handle must not be used again. Any further calls will return an error. All transaction handles must be committed or aborted before closing databases and the environment.

