Annotate your struct with #[derive(Entity)] and (if it has secondary indexes) #[derive(SecondaryKey)]. Mark the primary-key field with #[primary_key] and each secondary-keyed field with #[secondary_key(name = "...", relate = ..., …)]: use noxu_persist::{Entity, EntitySerializer, PersistError, Result, SecondaryKey}; #[derive(Clone, Debug, PartialEq, Entity, SecondaryKey)]
struct User { /// Primary key. Field type must implement `noxu_persist::PrimaryKey` /// (built-in for all common scalars + `String` / `Vec<u8>`). #[primary_key] id: u64, /// Unique secondary index — each user has exactly one email and the /// email is unique across the store. #[secondary_key(name = "by_email", relate = OneToOne)] email: String, /// Many-to-one foreign-key secondary index. `Option<u64>` is /// auto-unwrapped: the secondary key type is `u64`, and entities /// with `dept_id == None` are simply omitted from the index /// (think SQL `NULL`). #[secondary_key( name = "by_dept", relate = ManyToOne, related_entity = "Department", on_related_entity_delete = NULLIFY )] dept_id: Option<u64>, name: String,
} /// You still write the serializer by hand — serialization format is
/// orthogonal to the entity declaration. Length-prefixed binary,
/// `bincode`, `serde_json`, etc. are all valid.
struct UserSerializer; impl EntitySerializer<User> for UserSerializer { fn serialize(&self, u: &User) -> Result<Vec<u8>> { use noxu_persist::FieldEncoder; let mut enc = FieldEncoder::new(); enc.write_u64(u.id); enc.write_string(&u.email); match u.dept_id { None => enc.write_u8(0), Some(d) => { enc.write_u8(1); enc.write_u64(d); } } enc.write_string(&u.name); Ok(enc.finish()) } fn deserialize(&self, bytes: &[u8]) -> Result<User> { use noxu_persist::FieldDecoder; let mut dec = FieldDecoder::new(bytes); let id = dec.read_u64()?; let email = dec.read_string()?; let has_dept = dec.read_u8()?; let dept_id = if has_dept == 0 { None } else { Some(dec.read_u64()?) }; let name = dec.read_string()?; Ok(User { id, email, dept_id, name }) }
}

