A composite key is just a struct with #[derive(PrimaryKey)] whose field types each already implement PrimaryKey: use noxu_persist::PrimaryKey; #[derive(Clone, Debug, PartialEq, Eq, Hash, PartialOrd, Ord, PrimaryKey)]
struct OrderKey { region: String, customer_id: u64,
} #[derive(Clone, Debug, PartialEq, noxu_persist::Entity)]
