For complex types you implement your own encoding. Write the fields to a Vec<u8> in the order that determines sort priority. The first bytes written have the highest sort weight. struct Point { x: i32, y: i32 } fn encode_point(p: &Point) -> DatabaseEntry { let mut buf = Vec::with_capacity(8); // Sort by x first, then y (big-endian so bytes sort correctly) buf.extend_from_slice(&(p.x ^ i32::MIN).to_be_bytes()); // sign-bit flip for signed sort buf.extend_from_slice(&(p.y ^ i32::MIN).to_be_bytes()); DatabaseEntry::from_vec(buf)
} fn decode_point(entry: &DatabaseEntry) -> Point { let bytes = entry.data(); let x = i32::from_be_bytes(bytes[0..4].try_into().unwrap()) ^ i32::MIN; let y = i32::from_be_bytes(bytes[4..8].try_into().unwrap()) ^ i32::MIN; Point { x, y }
} This technique (XOR with MIN before big-endian encoding) is the same approach used internally by IntBinding and LongBinding.

